const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
const T = Number(input[pos++]);
let results = [];
for (let tc = 0; tc < T; tc++) {
  const s = input[pos++];
  let flips = 0;
  let parity = 0; // 0 = normal, 1 = inverted
  for (let i = 0; i < s.length; i++) {
    const bit = s.charCodeAt(i) - 48;
    const effective = parity === 0 ? bit : 1 - bit;
    if (effective === 0) {
      flips++;
      parity ^= 1;
    }
  }
  results.push(String(flips));
}
console.log(results.join('\n'));
